// Extract and normalize message data
const message = $input.first().json.message;
const text = message.text || '';
const userId = message.from.id;
const chatId = message.chat.id;
const messageId = message.message_id;
const username = message.from.username || '';

// Detect content type using regex
let contentType = 'invalid';
let url = null;

const youtubeRegex = /(youtube\.com|youtu\.be)/i;
const urlRegex = /https?:\/\/[^\s]+/i;

if (youtubeRegex.test(text)) {
  contentType = 'youtube';
  url = text.match(urlRegex)?.[0];
} else if (urlRegex.test(text)) {
  contentType = 'article';
  url = text.match(urlRegex)?.[0];
} else if (text.length > 500) {
  contentType = 'text';
} else if (text.startsWith('/history')) {
  contentType = 'history';
} else if (text.startsWith('/start') || text.startsWith('/help')) {
  contentType = 'help';
} else {
  contentType = 'invalid';
}

return {
  json: {
    contentType,
    url,
    text,
    userId,
    chatId,
    messageId,
    username
  }
};

// Pass through text content directly
const input = $input.first().json;

return {
  json: {
    ...input,
    content: input.text,
    extractedTitle: 'Direct Text Submission'
  }
};

// Process YouTube transcript response
const input = $input.first().json;
const prevData = $input.item.json;

// Supadata returns transcript as array of segments or plain text
let transcript = '';
if (Array.isArray(input.content)) {
  transcript = input.content.map(s => s.text).join(' ');
} else if (typeof input.content === 'string') {
  transcript = input.content;
} else if (input.transcript) {
  transcript = Array.isArray(input.transcript) 
    ? input.transcript.map(s => s.text).join(' ')
    : input.transcript;
}

// Truncate if too long (keep under 100k chars for LLM)
if (transcript.length > 100000) {
  transcript = transcript.substring(0, 100000) + '\n\n[Content truncated due to length]';
}

return {
  json: {
    ...prevData,
    content: transcript,
    extractedTitle: input.title || 'YouTube Video'
  }
};

// Process Jina Reader response
const input = $input.first();
const prevData = $input.item.json;

// Jina returns markdown content in the body
let content = '';
let title = 'Article';

if (typeof input.json === 'string') {
  content = input.json;
} else if (input.json.data) {
  content = input.json.data;
  title = input.json.title || title;
} else {
  content = JSON.stringify(input.json);
}

// Extract title from markdown if present
const titleMatch = content.match(/^#\s+(.+)$/m);
if (titleMatch) {
  title = titleMatch[1];
}

// Truncate if too long
if (content.length > 50000) {
  content = content.substring(0, 50000) + '\n\n[Content truncated due to length]';
}

return {
  json: {
    ...prevData,
    content,
    extractedTitle: title
  }
};

// Return cached summary from Airtable
const airtableRecord = $input.first().json;
const messageData = $input.item.json;

return {
  json: {
    ...messageData,
    summary: airtableRecord.fields.summary,
    title: airtableRecord.fields.title,
    cached: true
  }
};

// Extract summary from OpenRouter response
const response = $input.first().json;
const messageData = $input.item.json;

const summary = response.choices?.[0]?.message?.content || 'Failed to generate summary';

// Extract title from summary
const titleMatch = summary.match(/\*\*Title\*\*:\s*(.+)/i);
const title = titleMatch ? titleMatch[1].trim() : messageData.extractedTitle || 'Summary';

return {
  json: {
    ...messageData,
    summary,
    title,
    cached: false,
    tokenUsage: response.usage?.total_tokens || 0
  }
};

// Merge cached and new summaries for sending
const items = $input.all();
return items;

// Format history for Telegram
const records = $input.all();
const messageData = $input.item.json;

if (records.length === 0) {
  return {
    json: {
      chatId: messageData.chatId,
      historyMessage: "You don't have any summaries yet. Send me a YouTube link or article to get started!"
    }
  };
}

let historyText = '*Your Recent Summaries:*\n\n';

records.forEach((record, index) => {
  const fields = record.json.fields || record.json;
  const title = fields.title || 'Untitled';
  const type = fields.content_type || 'unknown';
  const url = fields.url || '';

  historyText += `${index + 1}. *${title}*\n`;
  historyText += `   Type: ${type}\n`;
  if (url && !url.startsWith('text_')) {
    historyText += `   URL: ${url}\n`;
  }
  historyText += '\n';
});

return {
  json: {
    chatId: messageData.chatId,
    historyMessage: historyText
  }
};
